using System.Windows.Forms;

public class MainForm : Form
{
    private StatusStrip statusStrip;

    public MainForm()
    {
        statusStrip = new StatusStrip();
        // .NET 9: StatusStrip no longer defaults to ToolStripRenderMode.System.
        // Set explicitly to preserve the .NET 8 appearance.
        statusStrip.RenderMode = ToolStripRenderMode.System;
        Controls.Add(statusStrip);
    }
}

using System.ComponentModel;
using System.Drawing.Design;
using System.Windows.Forms.Design;

public class MyDropDownEditor : UITypeEditor
{
    public override object? EditValue(
        ITypeDescriptorContext? context,
        IServiceProvider provider,
        object? value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;

        if (editorService is null)
            return value;

        // .NET 9: DropDownControl parameter is now non-nullable.
        // Guard against null controls instead of passing null.
        var control = CreateDropDownControl(value);
        if (control is not null)
        {
            editorService.DropDownControl(control);
            value = GetValueFromControl(control);
        }

        return value;
    }

    private static System.Windows.Forms.Control? CreateDropDownControl(object? currentValue)
    {
        // Return null when no dropdown is appropriate; the caller skips the call.
        if (currentValue is null)
            return null;

        var listBox = new System.Windows.Forms.ListBox();
        listBox.Items.Add(currentValue);
        return listBox;
    }

    private static object? GetValueFromControl(System.Windows.Forms.Control control)
    {
        if (control is System.Windows.Forms.ListBox lb && lb.SelectedItem is not null)
            return lb.SelectedItem;
        return null;
    }
}

